import React, { useState } from "react";
import api from "../api/axios";
import { useNavigate, Link } from "react-router-dom";

export default function Register() {
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");          // ✅ NEW
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const navigate = useNavigate();

  async function handleRegister(e) {
    e.preventDefault();
    setError("");

    try {
      await api.post("/auth/register/", {
        username,
        email,           // ✅ SEND EMAIL
        password,
      });

      navigate("/login");
    } catch {
      setError("Username or email already exists");
    }
  }

  return (
    <>
      {/* 🔹 Embedded CSS */}
      <style>{`
        .auth-wrapper {
          min-height: 100vh;
          background: linear-gradient(
              rgba(0, 0, 0, 0.65),
              rgba(0, 0, 0, 0.65)
            ),
            url("/assets/images/glamp2.jpg") center / cover no-repeat;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 20px;
        }

        .auth-card {
          background: rgba(20, 20, 20, 0.9);
          padding: 40px 36px;
          border-radius: 14px;
          width: 100%;
          max-width: 420px;
          color: #fff;
          box-shadow: 0 25px 60px rgba(0, 0, 0, 0.6);
          text-align: center;
        }

        .auth-title {
          font-size: 28px;
          font-weight: 600;
          margin-bottom: 6px;
          letter-spacing: 1px;
        }

        .auth-subtitle {
          font-size: 14px;
          color: #ccc;
          margin-bottom: 30px;
        }

        .auth-field {
          text-align: left;
          margin-bottom: 18px;
        }

        .auth-field label {
          font-size: 13px;
          color: #aaa;
          margin-bottom: 6px;
          display: block;
        }

        .auth-field input {
          width: 100%;
          padding: 12px 14px;
          border-radius: 8px;
          border: none;
          background: #2a2a2a;
          color: #fff;
          font-size: 14px;
        }

        .auth-field input:focus {
          outline: none;
          background: #333;
        }

        .auth-btn {
          width: 100%;
          padding: 14px;
          margin-top: 12px;
          border: none;
          border-radius: 30px;
          background: linear-gradient(135deg, #c8a45d, #b48a45);
          color: #111;
          font-weight: 600;
          letter-spacing: 1px;
          cursor: pointer;
          transition: all 0.3s ease;
        }

        .auth-btn:hover {
          transform: translateY(-1px);
          box-shadow: 0 10px 25px rgba(200, 164, 93, 0.4);
        }

        .auth-error {
          background: rgba(255, 80, 80, 0.15);
          border: 1px solid rgba(255, 80, 80, 0.4);
          color: #ff9b9b;
          padding: 10px;
          border-radius: 8px;
          font-size: 13px;
          margin-bottom: 16px;
        }

        .auth-footer {
          margin-top: 22px;
          font-size: 14px;
          color: #bbb;
        }

        .auth-footer a {
          color: #c8a45d;
          text-decoration: none;
        }

        .auth-footer a:hover {
          text-decoration: underline;
        }

        .auth-back-btn {
          display: block;
          margin-top: 16px;
          text-align: center;
          font-size: 14px;
          color: #bbb;
          text-decoration: none;
        }

        .auth-back-btn:hover {
          color: #c8a45d;
        }
      `}</style>

      {/* 🔹 UI */}
      <div className="auth-wrapper">
        <div className="auth-card fade-up">
          <h2 className="auth-title">Create Account</h2>
          <p className="auth-subtitle">
            Join us and start your luxury experience
          </p>

          {error && <div className="auth-error">{error}</div>}

          <form onSubmit={handleRegister}>
            <div className="auth-field">
              <label>Username</label>
              <input
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="Choose a username"
                required
              />
            </div>

            {/* ✅ EMAIL FIELD */}
            <div className="auth-field">
              <label>Email Address</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="Enter your email"
                required
              />
            </div>

            <div className="auth-field">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Create a password"
                required
              />
            </div>

            <Link to="/" className="auth-back-btn">
              ← Back to Home
            </Link>

            <button className="auth-btn" type="submit">
              REGISTER
            </button>
          </form>

          <div className="auth-footer">
            Already have an account?{" "}
            <Link to="/login">Login</Link>
          </div>
        </div>
      </div>
    </>
  );
}
